import SwiftUI
import SwiftData
import StoreKit import MessageUI import LocalAuthentication // MARK: - ─── 设置主页面 ─── /// 设置主页面 — 工程级重构版（分段提取，统一数据源，可测试） @MainActor struct SettingsView: View { @EnvironmentObject private var subManager: SubscriptionManager @ObservedObject private var syncObserver = CloudSyncObserver.shared // MARK: 状态 @State private var showExportOptions = false @State private var showImportOptions = false @State private var showResetConfirm = false @State private var showCacheAlert = false @State private var showLicenses = false @State private var showAppIconPicker = false @State private var showShortcutSetup = false @State private var showAuthorPasscodeAlert = false @State private var authorPasscodeInput = "" @State private var showCodeGenerator = false @State private var showRedeemSheet = false @State private var showMailComposer = false @State private var databaseSize = "计算中..." @State private var estimatedCacheSize = "计算中..." // MARK: 持久化设置 @AppStorage("app.appearance") private var appAppearanceRaw = AppAppearance.system.rawValue @AppStorage("app.icon") private var appIconRaw = "默认" @AppStorage("caseModuleEnabled") private var caseModuleEnabled: Bool = true @AppStorage("appLockEnabled") private var appLockEnabled: Bool = false @AppStorage("biometricLockEnabled") private var biometricLockEnabled: Bool = true @AppStorage("lockTimeout") private var lockTimeout: Int = 30 @AppStorage("iCloudSyncEnabled") private var iCloudSyncEnabled: Bool = true @AppStorage("syncOnCellular") private var syncOnCellular: Bool = false @AppStorage("reduceMotionOverride") private var reduceMotionOverride: Bool = false @AppStorage("siriQuickAddPerson") private var siriQuickAddPerson: Bool = true @AppStorage("siriQuickSearch") private var siriQuickSearch: Bool = true @AppStorage("userProfileName") private var userProfileName: String = "" @AppStorage("userProfileOrg") private var userProfileOrg: String = "" // 通知偏好 @AppStorage("notif.caseProgress") private var notifCaseProgress: Bool = true @AppStorage("notif.eventReminder") private var notifEventReminder: Bool = true @AppStorage("notif.deadlineAlert") private var notifDeadlineAlert: Bool = true @AppStorage("notif.contactActive") private var notifContactActive: Bool = false @AppStorage("notif.systemNotice") private var notifSystemNotice: Bool = true // 开发者密码（AppStorage 存储，生产环境建议 Keychain） @AppStorage("authorPasscode") private var authorPasscode: String = "" // MARK: 计算属性 private var appVersion: String { let version = Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0" let build = Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "1" return "\(version) (\(build))" } private var hasBiometric: Bool { let context = LAContext() return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil) } private var biometricType: String { let context = LAContext() _ = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil) switch context.biometryType { case .faceID: return "面容 ID" case .touchID: return "触控 ID" default: return "密码" } } var body: some View { NavigationStack { List { iCloudAccountSection membershipSection modulesSection notificationsSection appearanceSection securitySection privacySection syncStorageSection dataSection shortcutsSection aboutSection developerEntry } .listStyle(.insetGrouped) .scrollContentBackground(.hidden) .background(Color.surfaceLight) .navigationTitle("设置") .sheet(isPresented: $subManager.showUpgradeSheet) { UpgradeSheet().environmentObject(subManager) } .sheet(isPresented: $showRedeemSheet) { RedeemSheet().environmentObject(subManager) } .sheet(isPresented: $showCodeGenerator) { CodeGeneratorSheet() } .sheet(isPresented: $showLicenses) { LicensesView() } .sheet(isPresented: $showAppIconPicker) { AppIconPickerView(selectedIcon: $appIconRaw) } .sheet(isPresented: $showShortcutSetup) { ShortcutSetupView() } .confirmationDialog("导出数据", isPresented: $showExportOptions, titleVisibility: .visible) { Button("导出为 JSON") { performExport(format: .json) } Button("导出为 CSV") { performExport(format: .csv) } Button("取消", role: .cancel) {} } message: { Text("选择导出格式。JSON 包含完整数据结构和关联关系，CSV 适合在电子表格中查看。") } .confirmationDialog("导入数据", isPresented: $showImportOptions, titleVisibility: .visible) { Button("从 JSON 导入") { performImport(format: .json) } Button("从 CSV 导入案件") { performImport(format: .csv) } Button("取消", role: .cancel) {} } message: { Text("导入将合并到当前数据，不会覆盖已有记录。") } .alert("重置所有数据", isPresented: $showResetConfirm) { Button("取消", role: .cancel) {} Button("重置", role: .destructive) { performDataReset() } } message: { Text("此操作将删除所有案件、人脉、事件数据。数据一经删除无法恢复。建议先导出备份。") } .alert("清除缓存", isPresented: $showCacheAlert) { Button("取消", role: .cancel) {} Button("清除", role: .destructive) { performCacheClear() } } message: { Text("清除图片和缩略图缓存。核心数据不受影响，缓存将重新生成。") } .alert(authorPasscode.isEmpty ? "设置作者密码" : "开发者验证", isPresented: $showAuthorPasscodeAlert) { SecureField(authorPasscode.isEmpty ? "设定密码" : "输入密码", text: $authorPasscodeInput) Button("确定") { verifyAndOpenGenerator() } Button("取消", role: .cancel) { authorPasscodeInput = "" } } message: { if authorPasscode.isEmpty { Text("请设定开发者密码，之后长按版本号将需要验证。") } } .onAppear { computeStorageInfo() } } } // MARK: - iCloud 账户 @ViewBuilder private var iCloudAccountSection: some View { Section { // ── 账户状态 ── VStack(spacing: Spacing.sm) { HStack(spacing: Spacing.md) { Image(systemName: syncObserver.isCloudAvailable ? "person.icloud.fill" : "person.icloud.slash") .font(.system(size: 20)) .foregroundColor(syncObserver.isCloudAvailable ? .statusInfo : .statusWarning) .frame(width: 28) VStack(alignment: .leading, spacing: 2) { Text(syncObserver.isCloudAvailable ? (syncObserver.accountName ?? "iCloud 账户") : "iCloud 不可用") .font(.cnBody) .foregroundColor(.textPrimary) Text(syncObserver.isCloudAvailable ? "数据通过你的 iCloud 账户同步" : "请前往系统设置登录 iCloud") .font(.cnCaption1) .foregroundColor(.textTertiary) } } } .padding(.vertical, Spacing.xs) // ── 同步状态 ── HStack(spacing: Spacing.md) { Image(systemName: syncObserver.syncStatus.systemImage) .font(.system(size: 20)) .foregroundColor(syncObserver.syncStatus.indicatorColor) .frame(width: 28) Text("同步状态") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Text(syncObserver.syncStatus.displayText) .font(.cnCaption1) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) // ── 用户档案 ── VStack(spacing: Spacing.sm) { Divider() HStack(spacing: Spacing.md) { Image(systemName: "person.text.rectangle.fill") .font(.system(size: 20)) .foregroundColor(.tealLink) .frame(width: 28) Text("用户档案") .font(.cnBody) .foregroundColor(.textPrimary) } TextField("你的姓名", text: $userProfileName) .font(.cnCallout) .textContentType(.name) .padding(.leading, 28 + Spacing.md) TextField("执业机构（选填）", text: $userProfileOrg) .font(.cnCallout) .textContentType(.organizationName) .padding(.leading, 28 + Spacing.md) } .padding(.vertical, Spacing.xs) } header: { Text(SettingsSection.iCloudAccount.title) } footer: { if !syncObserver.isCloudAvailable { Text("iCloud 不可用时，数据仅保存在本机。开启 iCloud 后数据将自动同步。") } else { Text("档案仅保存在本机，不上传。用于导出数据和 App 内文案个性化。") } } } // MARK: - 会员 @ViewBuilder private var membershipSection: some View { Section { VStack(spacing: Spacing.sm) { // 状态行 HStack { ZStack { Circle() .fill(subManager.isPro ? Color.tealLink.opacity(0.15) : Color.textTertiary.opacity(0.1)) .frame(width: 40, height: 40) Image(systemName: subManager.isPro ? "crown.fill" : "crown") .font(.system(size: 20)) .foregroundColor(subManager.isPro ? .tealLink : .textTertiary) } VStack(alignment: .leading, spacing: 2) { Text(subManager.isPro ? "屿连 Pro" : "免费版") .font(.cnHeadline) .foregroundColor(.textPrimary) Text(subManager.isPro ? (subManager.proSource == .invitation ? "邀请兑换 · 还剩 \(subManager.invitationDaysRemaining) 天" : "已解锁全部功能，感谢支持") : "¥99/年 解锁无限使用") .font(.cnCaption1) .foregroundColor(.textTertiary) } Spacer() if !subManager.isPro { Button { subManager.showUpgradeSheet = true } label: { Text("升级") .font(.cnCaption2.weight(.bold)) .foregroundColor(.white) .padding(.horizontal, Spacing.md) .padding(.vertical, Spacing.sm) .background( RoundedRectangle(cornerRadius: CornerRadius.tag) .fill(Color.tealLink) ) } } if subManager.proSource == .invitation { Image(systemName: "gift.fill") .font(.system(size: 14)) .foregroundColor(.tealLink) } } // 用量条 VStack(spacing: 6) { usageBar( label: "人脉联系人", icon: "person.2", count: subManager.personCount, limit: SubscriptionManager.freePersonLimit, isPro: subManager.isPro ) usageBar( label: "案件 · 事件", icon: "folder", count: subManager.caseEventCount, limit: SubscriptionManager.freeCaseEventLimit, isPro: subManager.isPro ) } // 邀请码入口 if !subManager.isPro || subManager.proSource == .invitation { Divider() Button { showRedeemSheet = true } label: { HStack { Image(systemName: "gift") .font(.system(size: 14)) .foregroundColor(.tealLink) Text("兑换邀请码") .font(.cnCallout) .foregroundColor(.textPrimary) Spacer() Image(systemName: "chevron.right") .font(.system(size: 12, weight: .medium)) .foregroundColor(.textTertiary) } } } } .padding(.vertical, Spacing.sm) } header: { Text(SettingsSection.membership.title) } } // MARK: - 功能模块 @ViewBuilder private var modulesSection: some View { Section { settingsToggleRow( title: "案件管理", subtitle: "关闭后案件板块从主界面隐藏。事件和日历不受影响。", systemImage: "folder.fill", iconColor: .tealLink, isOn: $caseModuleEnabled ) } header: { Text(SettingsSection.modules.title) } } // MARK: - 通知 @ViewBuilder private var notificationsSection: some View { Section { NavigationLink { NotificationDetailView( notifCaseProgress: $notifCaseProgress, notifEventReminder: $notifEventReminder, notifDeadlineAlert: $notifDeadlineAlert, notifContactActive: $notifContactActive, notifSystemNotice: $notifSystemNotice ) } label: { HStack(spacing: Spacing.md) { Image(systemName: "bell.fill") .font(.system(size: 20)) .foregroundColor(.coralWarm) .frame(width: 28) Text("通知偏好") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Text(notificationSummary) .font(.cnCaption1) .foregroundColor(.textTertiary) Image(systemName: "chevron.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } } header: { Text(SettingsSection.notifications.title) } } private var notificationSummary: String { let enabled = [notifCaseProgress, notifEventReminder, notifDeadlineAlert, notifContactActive, notifSystemNotice] .filter { $0 }.count let total = NotificationCategory.allCases.count if enabled == total { return "全部开启" } if enabled == 0 { return "全部关闭" } return "\(enabled)/\(total) 项开启" } // MARK: - 外观 @ViewBuilder private var appearanceSection: some View { Section { // 深色模式 HStack(spacing: Spacing.md) { Image(systemName: currentAppearance.systemImage) .font(.system(size: 20)) .foregroundColor(.statusInfo) .frame(width: 28) Text("深色模式") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Picker("", selection: $appAppearanceRaw) { ForEach(AppAppearance.allCases, id: \.rawValue) { option in Text(option.rawValue).tag(option.rawValue) } } .pickerStyle(.menu) .tint(.textSecondary) .onChange(of: appAppearanceRaw) { _, newValue in applyAppearance(newValue) } } .padding(.vertical, Spacing.xs) // App 图标 Button { showAppIconPicker = true } label: { HStack(spacing: Spacing.md) { Image(systemName: "app.badge.fill") .font(.system(size: 20)) .foregroundColor(.tealLink) .frame(width: 28) Text("App 图标") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Text(AppIconOption(rawValue: appIconRaw)?.rawValue ?? "默认") .font(.cnCaption1) .foregroundColor(.textTertiary) Image(systemName: "chevron.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } // 减弱动态效果 settingsToggleRow( title: "减弱动态效果", systemImage: "slowmo", iconColor: .textSecondary, isOn: $reduceMotionOverride ) } header: { Text(SettingsSection.appearance.title) } } private var currentAppearance: AppAppearance { AppAppearance(rawValue: appAppearanceRaw) ?? .system } private func applyAppearance(_ rawValue: String) { guard let appearance = AppAppearance(rawValue: rawValue), let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene, let window = windowScene.windows.first else { return } switch appearance { case .system: window.overrideUserInterfaceStyle = .unspecified case .light: window.overrideUserInterfaceStyle = .light case .dark: window.overrideUserInterfaceStyle = .dark } } // MARK: - 安全 @ViewBuilder private var securitySection: some View { Section { settingsToggleRow( title: "应用锁", subtitle: hasBiometric ? "锁定后需\(biometricType)或密码解锁" : "锁定后需密码解锁", systemImage: "lock.fill", iconColor: .coralWarm, isOn: $appLockEnabled ) if appLockEnabled && hasBiometric { settingsToggleRow( title: biometricType, subtitle: "使用\(biometricType)快速解锁", systemImage: biometricType.contains("面容") ? "faceid" : "touchid", iconColor: .statusInfo, isOn: $biometricLockEnabled ) } if appLockEnabled { HStack(spacing: Spacing.md) { Image(systemName: "timer") .font(.system(size: 20)) .foregroundColor(.textSecondary) .frame(width: 28) Text("锁定延时") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Picker("", selection: $lockTimeout) { Text("立即").tag(0) Text("30 秒").tag(30) Text("1 分钟").tag(60) Text("5 分钟").tag(300) } .pickerStyle(.menu) .tint(.textSecondary) } .padding(.vertical, Spacing.xs) } } header: { Text(SettingsSection.security.title) } footer: { if appLockEnabled { Text("应用进入后台超过设定时间后，再次打开需要验证身份。") } } } // MARK: - 隐私与数据 @ViewBuilder private var privacySection: some View { Section { VStack(alignment: .leading, spacing: Spacing.md) { HStack(spacing: Spacing.md) { Image(systemName: "shield.checkered") .font(.system(size: 20)) .foregroundColor(.statusSuccess) .frame(width: 28) VStack(alignment: .leading, spacing: 2) { Text("数据完全本地化") .font(.cnBody) .foregroundColor(.textPrimary) Text("所有案件、人脉和事件数据仅存储在你的设备和 iCloud 账户中。") .font(.cnCaption1) .foregroundColor(.textTertiary) } } Divider() HStack(spacing: Spacing.md) { Image(systemName: "eye.slash.fill") .font(.system(size: 20)) .foregroundColor(.statusInfo) .frame(width: 28) VStack(alignment: .leading, spacing: 2) { Text("我们无法读取你的数据") .font(.cnBody) .foregroundColor(.textPrimary) Text("屿连不上传、不收集、不分析你的任何业务数据。端到端加密由 Apple 提供。") .font(.cnCaption1) .foregroundColor(.textTertiary) } } Divider() HStack(spacing: Spacing.md) { Image(systemName: "key.fill") .font(.system(size: 20)) .foregroundColor(.coralWarm) .frame(width: 28) VStack(alignment: .leading, spacing: 2) { Text("你的数据属于你") .font(.cnBody) .foregroundColor(.textPrimary) Text("随时导出全部数据为 JSON 或 CSV 格式，一键带走。删除 App 后 iCloud 数据可手动清除。") .font(.cnCaption1) .foregroundColor(.textTertiary) } } } .padding(.vertical, Spacing.sm) } header: { Text(SettingsSection.privacy.title) } } // MARK: - 同步与储存 @ViewBuilder private var syncStorageSection: some View { Section { VStack(spacing: 0) { settingsToggleRow( title: "iCloud 同步", subtitle: "在您的 Apple 设备间同步数据", systemImage: "icloud.fill", iconColor: .statusInfo, isOn: $iCloudSyncEnabled ) if iCloudSyncEnabled { settingsToggleRow( title: "允许蜂窝数据同步", subtitle: "关闭后仅在 Wi-Fi 下同步，节省流量", systemImage: "cellularbars", iconColor: .textTertiary, isOn: $syncOnCellular ) } } // 储存信息 VStack(spacing: Spacing.sm) { HStack(spacing: Spacing.md) { Image(systemName: syncObserver.syncStatus.systemImage) .font(.system(size: 14)) .foregroundColor(syncObserver.syncStatus.indicatorColor) Text(syncObserver.syncStatus.displayText) .font(.cnCaption1) .foregroundColor(.textTertiary) Spacer() } Divider() storageInfoRow(label: "数据库大小", value: databaseSize) storageInfoRow(label: "缓存大小", value: estimatedCacheSize) HStack { Spacer() Button("清除缓存") { showCacheAlert = true } .font(.cnCaption1) .foregroundColor(.tealLink) Spacer() } .padding(.top, Spacing.xs) } .padding(.vertical, Spacing.sm) } header: { Text(SettingsSection.syncStorage.title) } } // MARK: - 数据管理 @ViewBuilder private var dataSection: some View { Section { Button { showExportOptions = true } label: { settingsRowContent(title: "导出数据", systemImage: "arrow.up.doc.fill", iconColor: .tealLink) } Button { showImportOptions = true } label: { settingsRowContent(title: "导入数据", systemImage: "arrow.down.doc.fill", iconColor: .tealLink) } } header: { Text(SettingsSection.data.title) } footer: { Text("支持 JSON（完整数据）和 CSV（案件表格）格式。导入为合并模式，不会覆盖已有记录。") } Section { Button(role: .destructive) { showResetConfirm = true } label: { HStack { Image(systemName: "trash.fill") .font(.system(size: 20)) .foregroundColor(.statusError) .frame(width: 28) Text("重置所有数据") .foregroundColor(.statusError) } .padding(.vertical, Spacing.xs) } } } // MARK: - Siri 与快捷指令 @ViewBuilder private var shortcutsSection: some View { Section { settingsToggleRow( title: "快速添加联系人", subtitle: "「嘿 Siri，用屿连添加联系人」", systemImage: "person.badge.plus", iconColor: .tealLink, isOn: $siriQuickAddPerson ) settingsToggleRow( title: "快速搜索", subtitle: "「嘿 Siri，在屿连里搜索[关键词]」", systemImage: "magnifyingglass", iconColor: .statusInfo, isOn: $siriQuickSearch ) Button { showShortcutSetup = true } label: { HStack(spacing: Spacing.md) { Image(systemName: "square.grid.3x3.topleft.filled") .font(.system(size: 20)) .foregroundColor(.coralWarm) .frame(width: 28) Text("管理快捷指令") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "chevron.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } } header: { Text(SettingsSection.shortcuts.title) } footer: { Text("Siri 快捷指令让你无需打开 App 即可完成常用操作。在「快捷指令」App 中可进一步自定义。") } } // MARK: - 关于 @ViewBuilder private var aboutSection: some View { Section { // 版本 HStack(spacing: Spacing.md) { Image(systemName: "info.circle.fill") .font(.system(size: 20)) .foregroundColor(.textTertiary) .frame(width: 28) Text("版本") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Text(appVersion) .font(.cnCaption1) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) // 评分 Button { requestAppReview() } label: { HStack(spacing: Spacing.md) { Image(systemName: "star.fill") .font(.system(size: 20)) .foregroundColor(.coralWarm) .frame(width: 28) Text("在 App Store 评分") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "arrow.up.forward.app") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } // 发送反馈 Button { showMailComposer = true } label: { HStack(spacing: Spacing.md) { Image(systemName: "envelope.fill") .font(.system(size: 20)) .foregroundColor(.statusInfo) .frame(width: 28) Text("发送反馈") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "chevron.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } .disabled(!MFMailComposeViewController.canSendMail()) // 开源许可 Button { showLicenses = true } label: { HStack(spacing: Spacing.md) { Image(systemName: "doc.text.fill") .font(.system(size: 20)) .foregroundColor(.textSecondary) .frame(width: 28) Text("开源许可") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "chevron.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } // 隐私政策 & 服务条款 Link(destination: URL(string: "https://islandlink.app/privacy")!) { HStack(spacing: Spacing.md) { Image(systemName: "hand.raised.fill") .font(.system(size: 20)) .foregroundColor(.textSecondary) .frame(width: 28) Text("隐私政策") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "arrow.up.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } Link(destination: URL(string: "https://islandlink.app/terms")!) { HStack(spacing: Spacing.md) { Image(systemName: "list.clipboard.fill") .font(.system(size: 20)) .foregroundColor(.textSecondary) .frame(width: 28) Text("服务条款") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "arrow.up.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } } header: { Text(SettingsSection.about.title) } } // MARK: - 开发者入口（长按版本号） @ViewBuilder private var developerEntry: some View { Section { HStack { Spacer() VStack(spacing: 4) { Text("屿连 IslandLink") .font(.cnCaption1) .foregroundColor(.textTertiary) Text("由 SwiftUI 与 SwiftData 构建") .font(.cnCaption2) .foregroundColor(.textTertiary.opacity(0.7)) } .onLongPressGesture(minimumDuration: 3.0) { showAuthorPasscodeAlert = true } Spacer() } .listRowBackground(Color.clear) } } // MARK: - 辅助方法 private func settingsRowContent(title: String, systemImage: String, iconColor: Color) -> some View { HStack(spacing: Spacing.md) { Image(systemName: systemImage) .font(.system(size: 20)) .foregroundColor(iconColor) .frame(width: 28) Text(title) .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "chevron.right") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } .padding(.vertical, Spacing.xs) } private func settingsToggleRow( title: String, subtitle: String? = nil, systemImage: String, iconColor: Color, isOn: Binding<bool> ) -> some View { VStack(alignment: .leading, spacing: subtitle != nil ? 2 : 0) { HStack(spacing: Spacing.md) { Image(systemName: systemImage) .font(.system(size: 20)) .foregroundColor(iconColor) .frame(width: 28) Text(title) .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Toggle("", isOn: isOn) .labelsHidden() .tint(.tealLink) } if let subtitle { Text(subtitle) .font(.cnCaption1) .foregroundColor(.textTertiary) .padding(.leading, 28 + Spacing.md) } } .padding(.vertical, Spacing.xs) } private func storageInfoRow(label: String, value: String) -> some View { HStack { Text(label) .font(.cnCaption1) .foregroundColor(.textSecondary) Spacer() Text(value) .font(.cnCaption1.monospacedDigit()) .foregroundColor(.textTertiary) } } // ── 用量条 ── private func usageBar(label: String, icon: String, count: Int, limit: Int, isPro: Bool) -> some View { VStack(spacing: 4) { HStack { Image(systemName: icon) .font(.system(size: 12)) .foregroundColor(.textTertiary) Text(label) .font(.cnCaption1) .foregroundColor(.textSecondary) Spacer() Text(isPro ? "\(count) / 无限" : "\(count) / \(limit)") .font(.cnCaption1.monospacedDigit()) .foregroundColor(.textTertiary) } GeometryReader { geo in ZStack(alignment: .leading) { RoundedRectangle(cornerRadius: 2) .fill(Color.textTertiary.opacity(0.12)) .frame(height: 4) if !isPro { RoundedRectangle(cornerRadius: 2) .fill(barColor(count: count, limit: limit)) .frame(width: barWidth(count: count, limit: limit, totalWidth: geo.size.width), height: 4) } else { RoundedRectangle(cornerRadius: 2) .fill(Color.tealLink.opacity(0.6)) .frame(width: geo.size.width, height: 4) } } } .frame(height: 4) } } private func barWidth(count: Int, limit: Int, totalWidth: CGFloat) -> CGFloat { let ratio = min(CGFloat(count) / CGFloat(limit), 1.0) return max(ratio * totalWidth, 4) } private func barColor(count: Int, limit: Int) -> Color { let ratio = CGFloat(count) / CGFloat(limit) if ratio < 0.7 { return .tealLink } if ratio < 0.9 { return .statusWarning } return .coralWarm } // ── 储存计算 ── private func computeStorageInfo() { Task { // 估算数据库大小 let fileManager = FileManager.default if let supportDir = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask).first { let storeURL = supportDir.appendingPathComponent("default.store") if let attrs = try? fileManager.attributesOfItem(atPath: storeURL.path), let size = attrs[.size] as? Int64 { await MainActor.run { databaseSize = formatBytes(size) } } else { await MainActor.run { databaseSize = "—" } } } // 估算图片缓存 if let cacheDir = fileManager.urls(for: .cachesDirectory, in: .userDomainMask).first { let size = directorySize(at: cacheDir) await MainActor.run { estimatedCacheSize = size > 0 ? formatBytes(size) : "0 KB" } } } } private func directorySize(at url: URL) -> Int64 { let fileManager = FileManager.default guard let enumerator = fileManager.enumerator(at: url, includingPropertiesForKeys: [.fileSizeKey]) else { return 0 } var total: Int64 = 0 for case let fileURL as URL in enumerator { if let attrs = try? fileManager.attributesOfItem(atPath: fileURL.path), let size = attrs[.size] as? Int64 { total += size } } return total } private func formatBytes(_ bytes: Int64) -> String { let formatter = ByteCountFormatter() formatter.countStyle = .file return formatter.string(fromByteCount: bytes) } // ── 操作 ── private enum ExportFormat { case json, csv } private enum ImportFormat { case json, csv } private func performExport(format: ExportFormat) { // TODO: 实现具体导出逻辑 // ExportManager.shared.export(format: format) } private func performImport(format: ImportFormat) { // TODO: 实现具体导入逻辑 // ImportManager.shared.import(format: format) } private func performDataReset() { // TODO: 实现数据重置逻辑 // DataManager.shared.resetAll() } private func performCacheClear() { if let cacheDir = FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first { try? FileManager.default.removeItem(at: cacheDir) try? FileManager.default.createDirectory(at: cacheDir, withIntermediateDirectories: true) } estimatedCacheSize = "0 KB" } private func requestAppReview() { guard let scene = UIApplication.shared.connectedScenes.first as? UIWindowScene else { return } SKStoreReviewController.requestReview(in: scene) } private func verifyAndOpenGenerator() { defer { authorPasscodeInput = "" } if authorPasscode.isEmpty { authorPasscode = authorPasscodeInput showCodeGenerator = true return } if authorPasscodeInput == authorPasscode { showCodeGenerator = true } } } // MARK: - 通知详情子页面 private struct NotificationDetailView: View { @Binding var notifCaseProgress: Bool @Binding var notifEventReminder: Bool @Binding var notifDeadlineAlert: Bool @Binding var notifContactActive: Bool @Binding var notifSystemNotice: Bool var body: some View { List { ForEach(NotificationCategory.allCases) { category in VStack(alignment: .leading, spacing: 2) { HStack(spacing: Spacing.md) { Image(systemName: category.systemImage) .font(.system(size: 20)) .foregroundColor(iconColor(for: category)) .frame(width: 28) VStack(alignment: .leading, spacing: 2) { Text(category.rawValue) .font(.cnBody) .foregroundColor(.textPrimary) Text(category.description) .font(.cnCaption1) .foregroundColor(.textTertiary) } Spacer() Toggle("", isOn: binding(for: category)) .labelsHidden() .tint(.tealLink) } } .padding(.vertical, Spacing.xs) } } .listStyle(.insetGrouped) .scrollContentBackground(.hidden) .background(Color.surfaceLight) .navigationTitle("通知偏好") .navigationBarTitleDisplayMode(.inline) } private func binding(for category: NotificationCategory) -> Binding<bool> { switch category { case .caseProgress: return $notifCaseProgress case .eventReminder: return $notifEventReminder case .deadlineAlert: return $notifDeadlineAlert case .contactActive: return $notifContactActive case .systemNotice: return $notifSystemNotice } } private func iconColor(for category: NotificationCategory) -> Color { switch category { case .caseProgress: return .tealLink case .eventReminder: return .statusInfo case .deadlineAlert: return .coralWarm case .contactActive: return .statusSuccess case .systemNotice: return .textSecondary } } } // MARK: - 开源许可页面 private struct LicensesView: View { var body: some View { List { Section { licenseRow(name: "GRDB.swift", license: "MIT", url: "https://github.com/groue/GRDB.swift") licenseRow(name: "SwiftSoup", license: "MIT", url: "https://github.com/scinfu/SwiftSoup") } header: { Text("第三方开源库") } Section { licenseRow(name: "SF Symbols 6", license: "Apple", url: "https://developer.apple.com/sf-symbols/") licenseRow(name: "SwiftUI", license: "Apple", url: "https://developer.apple.com/xcode/swiftui/") licenseRow(name: "SwiftData", license: "Apple", url: "https://developer.apple.com/xcode/swiftdata/") } header: { Text("Apple 框架") } } .listStyle(.insetGrouped) .scrollContentBackground(.hidden) .background(Color.surfaceLight) .navigationTitle("开源许可") .navigationBarTitleDisplayMode(.inline) } private func licenseRow(name: String, license: String, url: String) -> some View { Link(destination: URL(string: url)!) { HStack { VStack(alignment: .leading, spacing: 2) { Text(name) .font(.cnBody) .foregroundColor(.textPrimary) Text(license) .font(.cnCaption1) .foregroundColor(.textTertiary) } Spacer() Image(systemName: "arrow.up.right") .font(.system(size: 12)) .foregroundColor(.textTertiary) } } } } // MARK: - App 图标选择器 private struct AppIconPickerView: View { @Binding var selectedIcon: String @Environment(\.dismiss) private var dismiss var body: some View { NavigationStack { List { ForEach(AppIconOption.allCases) { option in Button { selectedIcon = option.rawValue if let assetName = option.assetName { UIApplication.shared.setAlternateIconName(assetName) } else { UIApplication.shared.setAlternateIconName(nil) } } label: { HStack(spacing: Spacing.base) { Image(uiImage: previewImage(for: option)) .resizable() .aspectRatio(contentMode: .fit) .frame(width: 60, height: 60) .clipShape(RoundedRectangle(cornerRadius: 14)) .overlay( RoundedRectangle(cornerRadius: 14) .stroke(Color.divider, lineWidth: 1) ) Text(option.rawValue) .font(.cnBody) .foregroundColor(.textPrimary) Spacer() if option.rawValue == selectedIcon { Image(systemName: "checkmark.circle.fill") .foregroundColor(.tealLink) } } } .padding(.vertical, Spacing.xs) } } .listStyle(.insetGrouped) .scrollContentBackground(.hidden) .background(Color.surfaceLight) .navigationTitle("选择图标") .navigationBarTitleDisplayMode(.inline) .toolbar { ToolbarItem(placement: .confirmationAction) { Button("完成") { dismiss() } } } } } /// 工程角度：实际项目中应展示 App Icon 的预览图。这里用 SF Symbol 占位。 private func previewImage(for option: AppIconOption) -> UIImage { let config = UIImage.SymbolConfiguration(pointSize: 30) let image = UIImage(systemName: "dolphin", withConfiguration: config) ?? UIImage(systemName: "app.fill", withConfiguration: config)! return image.withTintColor(.systemTeal, renderingMode: .alwaysOriginal) } } // MARK: - 快捷指令设置页面 private struct ShortcutSetupView: View { var body: some View { List { Section { VStack(alignment: .leading, spacing: Spacing.sm) { HStack(spacing: Spacing.md) { Image(systemName: "bolt.fill") .font(.system(size: 28)) .foregroundColor(.coralWarm) Text("Siri 快捷指令") .font(.cnTitle3) .foregroundColor(.textPrimary) } Text("在「快捷指令」App 中创建自定义自动化流程，将屿连的常用操作与你的工作流深度集成。") .font(.cnCallout) .foregroundColor(.textSecondary) .fixedSize(horizontal: false, vertical: true) } .padding(.vertical, Spacing.sm) } Section { shortcutRow( title: "搜索人脉", description: "按姓名或角色搜索联系人", systemImage: "person.fill.questionmark", phrase: "在屿连里搜索" ) shortcutRow( title: "查看今日安排", description: "快速查看今日开庭和事件", systemImage: "calendar.day.timeline.left", phrase: "查看今日安排" ) shortcutRow( title: "添加事件", description: "口头记录新事件", systemImage: "calendar.badge.plus", phrase: "用屿连添加事件" ) } header: { Text("推荐快捷指令") } Section { Link(destination: URL(string: "shortcuts://")!) { HStack { Image(systemName: "square.grid.3x3.topleft.filled") .font(.system(size: 20)) .foregroundColor(.statusInfo) .frame(width: 28) Text("打开快捷指令 App") .font(.cnBody) .foregroundColor(.textPrimary) Spacer() Image(systemName: "arrow.up.forward.app") .font(.system(size: 14, weight: .medium)) .foregroundColor(.textTertiary) } } } footer: { Text("在「快捷指令」App 的「App」分类中可找到更多屿连快捷指令。") } } .listStyle(.insetGrouped) .scrollContentBackground(.hidden) .background(Color.surfaceLight) .navigationTitle("快捷指令") .navigationBarTitleDisplayMode(.inline) } private func shortcutRow(title: String, description: String, systemImage: String, phrase: String) -> some View { Button { // 通过 NSUserActivity donate Siri 快捷指令 } label: { HStack(spacing: Spacing.md) { Image(systemName: systemImage) .font(.system(size: 20)) .foregroundColor(.tealLink) .frame(width: 28) VStack(alignment: .leading, spacing: 2) { Text(title) .font(.cnBody) .foregroundColor(.textPrimary) Text(description) .font(.cnCaption1) .foregroundColor(.textTertiary) } Spacer() Image(systemName: "plus.circle") .font(.system(size: 20)) .foregroundColor(.tealLink) } .padding(.vertical, Spacing.xs) } } }
